<?php $h=static fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');$processSteps=$processSteps??[];$processCurrent=max(1,(int)($processCurrent??1)); ?><ol class="vo-process-steps" aria-label="Pasos de la operación"><?php foreach($processSteps as$i=>$step): ?><li class="<?= $i+1===$processCurrent?'is-current':($i+1<$processCurrent?'is-complete':'') ?>" <?= $i+1===$processCurrent?'aria-current="step"':'' ?>><span><?= $i+1 ?></span><?= $h($step) ?></li><?php endforeach; ?></ol>
